#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, C, D;
        scanf("%d %d %d %d", &N, &M, &C, &D);
        int MOD;
        scanf("%d", &MOD);
        int **carrots = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            carrots[i] = (int *)malloc(M * sizeof(int));
            for (int j = 0; j < M; j++) {
                carrots[i][j] = 0;
            }
        }
        for (int i = 0; i < C; i++) {
            int x, y;
            scanf("%d %d", &x, &y);
            carrots[x - 1][y - 1] = 1;
        }
        int **dp1 = (int **)malloc(N * sizeof(int *));
        int **dp2 = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            dp1[i] = (int *)malloc(M * sizeof(int));
            dp2[i] = (int *)malloc(M * sizeof(int));
            for (int j = 0; j < M; j++) {
                dp1[i][j] = 0;
                dp2[i][j] = 0;
            }
        }
        dp1[0][0] = 1;
        dp2[0][0] = 1;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                if (i < N - 1) {
                    dp1[i + 1][j] = (dp1[i + 1][j] + dp1[i][j]) % MOD;
                }
                if (j < M - 1) {
                    dp1[i][j + 1] = (dp1[i][j + 1] + dp1[i][j]) % MOD;
                }
                if (i < N - 1) {
                    dp2[i + 1][j] = (dp2[i + 1][j] + dp2[i][j]) % MOD;
                }
                if (j < M - 1) {
                    dp2[i][j + 1] = (dp2[i][j + 1] + dp2[i][j]) % MOD;
                }
            }
        }
        int ans = (dp1[N - 1][M - 1] * dp2[N - 1][M - 1]) % MOD;
        printf("%d\n", ans);
    }
    return 0;
}

